import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import response from './response.json';

interface MatchData {
  teams: {
    home: string;
    away: string;
  };
  score: {
    home: number;
    away: number;
  };
  period: string;
  timeRemaining: string;
}

interface KeyStat {
  category: string;
  home: string | number;
  away: string | number;
}

interface SportsData {
  match: MatchData;
  keyStats: KeyStat[];
}

export default function Widget() {
  const sportsData = response.data as SportsData;
  const { match, keyStats } = sportsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#303030' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 0.5 }}>
              {match.period} - {match.timeRemaining} remaining
            </Typography>
            <Typography variant="h6" sx={{ color: '#FFFFFF', fontWeight: 700 }}>
              {match.teams.home} vs {match.teams.away}
            </Typography>
            <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mt: 1 }}>
              <Typography variant="h4" sx={{ color: '#FFC107', fontWeight: 600 }}>
                {match.score.home}
              </Typography>
              <Typography variant="h4" sx={{ color: '#FF5722', fontWeight: 600 }}>
                {match.score.away}
              </Typography>
            </Stack>
          </Box>

          <Divider sx={{ bgcolor: '#FF5722' }} />

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Key Stats
            </Typography>
            <Stack spacing={1}>
              {keyStats.slice(0, 5).map((stat, index) => (
                <Stack direction="row" justifyContent="space-between" key={index}>
                  <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                    {stat.category}
                  </Typography>
                  <Typography variant="body2" sx={{ color: '#FFC107', fontWeight: 500 }}>
                    {stat.home}
                  </Typography>
                  <Typography variant="body2" sx={{ color: '#FF5722', fontWeight: 500 }}>
                    {stat.away}
                  </Typography>
                </Stack>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
